configfiles.configfile:
import os from aoptk.text_generation_api import TextGenerationAPI from aoptk.literature.pdf import PDF from aoptk.literature.pymupdf_parser import PymupdfParser
publication_id = os.path.splitext("$input_file.element_identifier")[0] openai_key = os.environ.get("OPENAI_KEY") text_generation_api = TextGenerationAPI(model="$llm_model", api_key=openai_key)
if "${input_file.ext}" == "pdf": text = PymupdfParser([PDF("$input_file")]).get_publications()[0].full_text chemicals = text_generation_api.find_chemicals(text)
elif "${input_file.ext}" == "txt": with open("$input_file", "r") as f_in: text = f_in.read() chemicals = text_generation_api.find_chemicals(text) else: raise ValueError(f"Unsupported input file format: {input_ext}")
with open("chemicals.tsv", "w") as f_out: f_out.write("id\tchemical\n") for chemical in chemicals: f_out.write(f"{publication_id}\t{chemical.name}\n")
